SELECT count(*) FROM role_type, cast_info, title, movie_companies, char_name, company_name, movie_info, company_type, info_type WHERE cast_info.role_id = role_type.id AND cast_info.movie_id = title.id AND movie_companies.movie_id = title.id AND cast_info.person_role_id = char_name.id AND movie_companies.company_id = company_name.id AND movie_info.movie_id = title.id AND movie_companies.company_type_id = company_type.id AND movie_info.info_type_id = info_type.id;